import warnings
import uuid
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

def _build_matmul_at_bt_ext():
    cpp_src = r"""
    #include <torch/extension.h>
    torch::Tensor matmul_at_bt(torch::Tensor A, torch::Tensor B);
    """

    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    // Computes C = A.T @ B.T given:
    // A: [K, M], B: [N, K] -> C: [M, N]
    // Implemented as C = (B @ A).T to leverage cuBLAS-backed at::matmul efficiently.
    torch::Tensor matmul_at_bt(torch::Tensor A, torch::Tensor B) {
        TORCH_CHECK(A.is_cuda() && B.is_cuda(), "Inputs must be CUDA tensors");
        TORCH_CHECK(A.scalar_type() == at::kFloat && B.scalar_type() == at::kFloat, "Inputs must be float32");
        TORCH_CHECK(A.dim() == 2 && B.dim() == 2, "Inputs must be 2D");
        // A: [K, M], B: [N, K]
        TORCH_CHECK(B.size(1) == A.size(0), "Shape mismatch: B.size(1) must equal A.size(0)");
        // Ensure contiguity only if needed
        if (!A.is_contiguous()) A = A.contiguous();
        if (!B.is_contiguous()) B = B.contiguous();
        // D = B @ A -> [N, M] using cuBLAS via ATen
        auto D = at::matmul(B, A);
        // Return transpose to get [M, N]; transpose is a view (no copy)
        return D.transpose(0, 1);
    }
    """

    name = f"atbt_ext_{uuid.uuid4().hex[:8]}"
    ext = load_inline(
        name=name,
        cpp_sources=[cpp_src],
        cuda_sources=[cuda_src],
        functions=["matmul_at_bt"],
        extra_cflags=["-O3"],
        extra_cuda_cflags=["-O3"],
        verbose=False,
    )
    return ext


class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that computes C = A.T @ B.T using a cuBLAS-backed
    ATen call wrapped in a torch.utils.cpp_extension.load_inline extension.
    Preserves the same __init__ and forward signatures.
    """
    _ext = None
    _ext_ok = None

    def __init__(self):
        super(ModelNew, self).__init__()
        # Build the extension exactly once
        if ModelNew._ext_ok is None:
            try:
                ModelNew._ext = _build_matmul_at_bt_ext()
                ModelNew._ext_ok = True
            except Exception as e:
                warnings.warn(f"Falling back to PyTorch matmul due to extension build failure: {e}")
                ModelNew._ext = None
                ModelNew._ext_ok = False
        self.use_ext = bool(ModelNew._ext_ok)

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Args:
            A: Tensor of shape (K, M)
            B: Tensor of shape (N, K)
        Returns:
            Tensor of shape (M, N) equal to A.T @ B.T
        """
        if (
            self.use_ext
            and A.is_cuda and B.is_cuda
            and A.dtype == torch.float32 and B.dtype == torch.float32
        ):
            return ModelNew._ext.matmul_at_bt(A, B)
        # Fallback to baseline PyTorch implementation
        return torch.matmul(A.T, B.T)

