import os
import uuid
import warnings
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Global cache for the extension so we build it only once per process
_bn2d_ext = None
_bn2d_ext_failed = False

def _build_bn2d_ext():
    global _bn2d_ext, _bn2d_ext_failed
    if _bn2d_ext is not None or _bn2d_ext_failed:
        return _bn2d_ext
    cpp_src = r"""
#include <torch/extension.h>

// Forward declaration
torch::Tensor batchnorm2d_forward(torch::Tensor input,
                                  torch::Tensor weight,
                                  torch::Tensor bias,
                                  torch::Tensor running_mean,
                                  torch::Tensor running_var,
                                  double eps,
                                  bool training,
                                  double momentum);
"""
    cuda_src = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

static __inline__ __device__ float warp_sum(float v) {
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

template<int VEC>
__global__ void reduce_channel_stats_kernel(const float* __restrict__ x,
                                            float* __restrict__ mean,
                                            float* __restrict__ var,
                                            int N, int C, int H, int W) {
  extern __shared__ float smem[];
  // One block per channel
  int c = blockIdx.x;
  int HW = H * W;
  int64_t M = (int64_t)N * (int64_t)HW;

  float thread_sum = 0.0f;
  float thread_sumsq = 0.0f;

  // Iterate over batches; within each, contiguous segment of size HW
  for (int n = 0; n < N; ++n) {
    const float* base = x + ((int64_t)n * C + c) * (int64_t)HW;

    // Vectorized main loop
    int idx = threadIdx.x * VEC;
    int stride = blockDim.x * VEC;

    if (VEC == 4) {
      for (int j = idx; j + 3 < HW; j += stride) {
        float4 v = reinterpret_cast<const float4*>(base)[j >> 2];
        thread_sum   += v.x + v.y + v.z + v.w;
        thread_sumsq += v.x*v.x + v.y*v.y + v.z*v.z + v.w*v.w;
      }
    } else if (VEC == 2) {
      for (int j = idx; j + 1 < HW; j += stride) {
        float2 v = reinterpret_cast<const float2*>(base)[j >> 1];
        thread_sum   += v.x + v.y;
        thread_sumsq += v.x*v.x + v.y*v.y;
      }
    } else {
      for (int j = idx; j < HW; j += stride) {
        float v = base[j];
        thread_sum   += v;
        thread_sumsq += v * v;
      }
    }

    // Scalar tail for non-divisible HW
    for (int j = ((HW / VEC) * VEC) + threadIdx.x; j < HW; j += blockDim.x) {
      float v = base[j];
      thread_sum   += v;
      thread_sumsq += v * v;
    }
  }

  // Warp reduction
  float sum = warp_sum(thread_sum);
  float sumsq = warp_sum(thread_sumsq);

  // Shared memory to reduce across warps
  int lane = threadIdx.x & 31;
  int warp_id = threadIdx.x >> 5;
  int num_warps = blockDim.x >> 5;

  if (lane == 0) {
    smem[warp_id * 2 + 0] = sum;
    smem[warp_id * 2 + 1] = sumsq;
  }
  __syncthreads();

  float total_sum = 0.0f;
  float total_sumsq = 0.0f;
  if (warp_id == 0) {
    float s_acc = 0.0f, s2_acc = 0.0f;
    for (int w = lane; w < num_warps; w += 32) {
      s_acc  += smem[w * 2 + 0];
      s2_acc += smem[w * 2 + 1];
    }
    s_acc  = warp_sum(s_acc);
    s2_acc = warp_sum(s2_acc);
    if (lane == 0) {
      total_sum = s_acc;
      total_sumsq = s2_acc;
      // Write back to smem for broadcast
      smem[0] = total_sum;
      smem[1] = total_sumsq;
    }
  }
  __syncthreads();
  if (warp_id != 0 || lane != 0) {
    total_sum = smem[0];
    total_sumsq = smem[1];
  }

  if (threadIdx.x == 0) {
    float mean_c = total_sum / (float)M;
    float var_c = total_sumsq / (float)M - mean_c * mean_c;
    if (var_c < 0.0f) var_c = 0.0f; // numerical guard
    mean[c] = mean_c;
    var[c] = var_c;
  }
}

__global__ void update_running_kernel(float* __restrict__ running_mean,
                                      float* __restrict__ running_var,
                                      const float* __restrict__ batch_mean,
                                      const float* __restrict__ batch_var,
                                      int C,
                                      double momentum) {
  int c = blockIdx.x * blockDim.x + threadIdx.x;
  if (c < C) {
    float rm = running_mean ? running_mean[c] : 0.0f;
    float rv = running_var ? running_var[c] : 0.0f;
    float bm = batch_mean[c];
    float bv = batch_var[c];
    float m = (float)momentum;
    if (running_mean) running_mean[c] = (1.0f - m) * rm + m * bm;
    if (running_var)  running_var[c]  = (1.0f - m) * rv + m * bv;
  }
}

template<int VEC>
__global__ void bn_forward_norm_kernel(const float* __restrict__ x,
                                       float* __restrict__ y,
                                       const float* __restrict__ mean,
                                       const float* __restrict__ var,
                                       const float* __restrict__ weight,
                                       const float* __restrict__ bias,
                                       int N, int C, int H, int W,
                                       double eps) {
  int c = blockIdx.x;    // channel
  int n = blockIdx.y;    // batch
  int HW = H * W;

  float m = mean[c];
  float inv_std = rsqrtf(var[c] + (float)eps);
  float g = weight ? weight[c] : 1.0f;
  float b = bias ? bias[c] : 0.0f;

  const float* base_x = x + ((int64_t)n * C + c) * (int64_t)HW;
  float* base_y = y + ((int64_t)n * C + c) * (int64_t)HW;

  int idx = threadIdx.x * VEC;
  int stride = blockDim.x * VEC;

  if (VEC == 4) {
    for (int j = idx; j + 3 < HW; j += stride) {
      float4 vx = reinterpret_cast<const float4*>(base_x)[j >> 2];
      float4 vy;
      vy.x = ((vx.x - m) * inv_std) * g + b;
      vy.y = ((vx.y - m) * inv_std) * g + b;
      vy.z = ((vx.z - m) * inv_std) * g + b;
      vy.w = ((vx.w - m) * inv_std) * g + b;
      reinterpret_cast<float4*>(base_y)[j >> 2] = vy;
    }
  } else if (VEC == 2) {
    for (int j = idx; j + 1 < HW; j += stride) {
      float2 vx = reinterpret_cast<const float2*>(base_x)[j >> 1];
      float2 vy;
      vy.x = ((vx.x - m) * inv_std) * g + b;
      vy.y = ((vx.y - m) * inv_std) * g + b;
      reinterpret_cast<float2*>(base_y)[j >> 1] = vy;
    }
  } else {
    for (int j = idx; j < HW; j += stride) {
      float vx = base_x[j];
      base_y[j] = ((vx - m) * inv_std) * g + b;
    }
  }
  // Tail
  for (int j = ((HW / VEC) * VEC) + threadIdx.x; j < HW; j += blockDim.x) {
    float vx = base_x[j];
    base_y[j] = ((vx - m) * inv_std) * g + b;
  }
}

