    int kernel_size, int stride, int padding, int dilation
) {
    // 3D grid mapping:
    // blockIdx.z: over N*C
    // blockIdx.y * blockDim.y + threadIdx.y: h_out
    // blockIdx.x * blockDim.x + threadIdx.x: w_out
    int nc = blockIdx.z;
    int n = nc / C;
    int c = nc - n * C;

    int w_out = blockIdx.x * blockDim.x + threadIdx.x;
    int h_out = blockIdx.y * blockDim.y + threadIdx.y;

    if (n >= N || c >= C || h_out >= H_out || w_out >= W_out) return;

    int h_start = h_out * stride - padding;
    int w_start = w_out * stride - padding;

    float maxval = -FLT_MAX;

    // Iterate over pooling window with dilation
    for (int kh = 0; kh < kernel_size; ++kh) {
        int h_in = h_start + kh * dilation;
        if ((unsigned)h_in >= (unsigned)H_in) continue;
        for (int kw = 0; kw < kernel_size; ++kw) {
            int w_in = w_start + kw * dilation;
            if ((unsigned)w_in >= (unsigned)W_in) continue;
            int in_idx = (((n * C + c) * H_in) + h_in) * W_in + w_in;
            float v = input[in_idx];
            maxval = v > maxval ? v : maxval;
        }
    }

    int out_idx = (((n * C + c) * H_out) + h_out) * W_out + w_out;
    output[out_idx] = maxval;
}

