import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Build/load the CUDA extension once at import time
_kb_ext = None
try:
    _kb_ext = load_inline(
        name="kb_ext",
        cpp_sources=[
            r'''
            #include <torch/extension.h>
            at::Tensor conv_transpose3d_forward(torch::Tensor input,
                                                torch::Tensor weight,
                                                torch::Tensor bias,
                                                int64_t stride,
                                                int64_t padding,
                                                int64_t dilation,
                                                bool has_bias);
            '''
        ],
        cuda_sources=[
            r'''
            #include <torch/extension.h>
            #include <ATen/cuda/CUDAContext.h>
            #include <cuda_runtime.h>

            template <typename scalar_t>
            __global__ void convtranspose3d_forward_kernel(
                const scalar_t* __restrict__ input,
                const scalar_t* __restrict__ weight,
                scalar_t* __restrict__ output,
                int N, int Cin, int Cout,
                int Di, int Hi, int Wi,
                int Do, int Ho, int Wo,
                int kD, int kH, int kW,
                int stride, int padding, int dilation)
            {
                long long total = (long long)N * Cin * Di * Hi * Wi;
                long long idx = blockIdx.x * (long long)blockDim.x + threadIdx.x;
                if (idx >= total) return;

                long long t = idx;
                int iw = (int)(t % Wi); t /= Wi;
                int ih = (int)(t % Hi); t /= Hi;
                int id = (int)(t % Di); t /= Di;
                int ic = (int)(t % Cin); t /= Cin;
                int n  = (int)t;

                scalar_t in_val = input[((((long long)n * Cin + ic) * Di + id) * Hi + ih) * Wi + iw];

                long long HoWo = (long long)Ho * (long long)Wo;
                long long DoHoWo = (long long)Do * HoWo;

                for (int oc = 0; oc < Cout; ++oc) {
                    long long out_base = ((long long)n * Cout + oc) * DoHoWo;
                    long long w_base = (((long long)ic) * Cout + oc) * (long long)kD * (long long)kH * (long long)kW;
                    for (int kd = 0; kd < kD; ++kd) {
                        int od = id * stride - padding + kd * dilation;
                        if (od < 0 || od >= Do) continue;
                        for (int kh = 0; kh < kH; ++kh) {
                            int oh = ih * stride - padding + kh * dilation;
                            if (oh < 0 || oh >= Ho) continue;
                            for (int kw = 0; kw < kW; ++kw) {
                                int ow = iw * stride - padding + kw * dilation;
                                if (ow < 0 || ow >= Wo) continue;

                                long long out_index = out_base + (long long)od * HoWo + (long long)oh * (long long)Wo + (long long)ow;
                                long long w_index = w_base + (long long)kd * (long long)kH * (long long)kW
                                                              + (long long)kh * (long long)kW
                                                              + (long long)kw;
                                atomicAdd(&output[out_index], in_val * weight[w_index]);
                            }
                        }
                    }
                }
            }

            template <typename scalar_t>
            __global__ void add_bias_kernel(
                scalar_t* __restrict__ out,
                const scalar_t* __restrict__ bias,
                int N, int Cout, int Do, int Ho, int Wo)
            {
                long long total = (long long)N * Cout * Do * Ho * Wo;
                long long idx = blockIdx.x * (long long)blockDim.x + threadIdx.x;
                if (idx >= total) return;

                long long t = idx;
                t /= Wo; // ow
                t /= Ho; // oh
                t /= Do; // od
                int oc = (int)(t % Cout);
                out[idx] += bias[oc];
            }

            at::Tensor conv_transpose3d_forward(torch::Tensor input,
                                                torch::Tensor weight,
                                                torch::Tensor bias,
                                                int64_t stride,
                                                int64_t padding,
                                                int64_t dilation,
                                                bool has_bias)
            {
                TORCH_CHECK(input.is_cuda(), "input must be on CUDA");
                TORCH_CHECK(weight.is_cuda(), "weight must be on CUDA");
                TORCH_CHECK(!has_bias || bias.is_cuda(), "bias must be on CUDA when provided");
                TORCH_CHECK(input.dtype() == torch::kFloat32, "only float32 is supported for input");
                TORCH_CHECK(weight.dtype() == torch::kFloat32, "only float32 is supported for weight");
                TORCH_CHECK(!has_bias || bias.dtype() == torch::kFloat32, "only float32 is supported for bias");
                TORCH_CHECK(input.dim() == 5, "input must be 5D (N, Cin, Di, Hi, Wi)");
                TORCH_CHECK(weight.dim() == 5, "weight must be 5D (Cin, Cout, kD, kH, kW)");

                auto input_c = input.contiguous();
                auto weight_c = weight.contiguous();

                const int64_t N = input_c.size(0);
                const int64_t Cin = input_c.size(1);
                const int64_t Di = input_c.size(2);
                const int64_t Hi = input_c.size(3);
                const int64_t Wi = input_c.size(4);

                TORCH_CHECK(weight_c.size(0) == Cin, "weight.size(0) must equal input.size(1) (Cin)");
                const int64_t Cout = weight_c.size(1);
                const int64_t kD = weight_c.size(2);
                const int64_t kH = weight_c.size(3);
                const int64_t kW = weight_c.size(4);

                TORCH_CHECK(stride > 0 && padding >= 0 && dilation > 0, "stride, padding, dilation must be positive (padding can be zero)");

                const int64_t Do = (Di - 1) * stride - 2 * padding + dilation * (kD - 1) + 1;
                const int64_t Ho = (Hi - 1) * stride - 2 * padding + dilation * (kH - 1) + 1;
                const int64_t Wo = (Wi - 1) * stride - 2 * padding + dilation * (kW - 1) + 1;

                TORCH_CHECK(Do > 0 && Ho > 0 && Wo > 0, "Computed output dimensions must be positive");

                auto out = torch::zeros({N, Cout, Do, Ho, Wo}, input_c.options());

                cudaStream_t stream = at::cuda::getCurrentCUDAStream();

                const int threads = 256;
                const long long total_in = N * Cin * Di * Hi * Wi;
                const int blocks = (int)((total_in + threads - 1LL) / threads);

                convtranspose3d_forward_kernel<float><<<blocks, threads, 0, stream>>>(
                    input_c.data_ptr<float>(),
                    weight_c.data_ptr<float>(),
                    out.data_ptr<float>(),
                    (int)N, (int)Cin, (int)Cout,
                    (int)Di, (int)Hi, (int)Wi,
                    (int)Do, (int)Ho, (int)Wo,
                    (int)kD, (int)kH, (int)kW,
                    (int)stride, (int)padding, (int)dilation
                );

                if (has_bias) {
                    TORCH_CHECK(bias.numel() == Cout, "bias must have length Cout");
                    auto bias_c = bias.contiguous();
                    const long long total_out = N * Cout * Do * Ho * Wo;
                    const int blocks_b = (int)((total_out + threads - 1LL) / threads);
                    add_bias_kernel<float><<<blocks_b, threads, 0, stream>>>(
