                        bias_c.data_ptr<float>(),
                        (int)N, (int)Cout, (int)Do, (int)Ho, (int)Wo
                    );
                }

                return out;
            }
            '''
        ],
        functions=["conv_transpose3d_forward"],
        with_cuda=True,
        extra_cflags=["-O3"],
        extra_cuda_cflags=["-O3"],
        verbose=False,
    )
