# SPDX-License-Identifier: MIT
# Single-file drop-in replacement for Model with accelerated forward using CUDA kernels.
import os
import time
import uuid
import warnings
from typing import Optional, Tuple

import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline


def _build_dwsep_extension():
    cpp_src = r"""
    #include <torch/extension.h>

    // Depthwise forward: input [N,C,H,W], weight [C,1,Kh,Kw], optional bias [C]
    torch::Tensor depthwise_forward(torch::Tensor input,
                                    torch::Tensor weight,
                                    torch::Tensor bias,
                                    int stride_h, int stride_w,
                                    int pad_h, int pad_w,
                                    int dilation_h, int dilation_w,
                                    int kernel_h, int kernel_w);

    // Pointwise forward: input [N,C,H,W], weight [OC,C,1,1], optional bias [OC]
    torch::Tensor pointwise_forward(torch::Tensor input,
                                    torch::Tensor weight,
                                    torch::Tensor bias);
    """

    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    // Helpers
    static inline int div_up(int a, int b) { return (a + b - 1) / b; }

    template<int TILE_H, int TILE_W>
    __global__ void depthwise_kernel(const float* __restrict__ x,
                                     const float* __restrict__ w,
                                     const float* __restrict__ b,
                                     float* __restrict__ y,
                                     int N, int C,
                                     int H, int W,
                                     int H_out, int W_out,
                                     int Kh, int Kw,
                                     int stride_h, int stride_w,
                                     int pad_h, int pad_w,
                                     int dilation_h, int dilation_w) {
      extern __shared__ float s_w[];
      // One block processes a TILE_H x TILE_W tile for a single (n, c) pair.
      int nc = blockIdx.z;
      int n = nc / C;
      int c = nc % C;

      // Load per-channel KxK weights to shared memory
      int num_weights = Kh * Kw;
      for (int idx = threadIdx.y * blockDim.x + threadIdx.x; idx < num_weights; idx += blockDim.x * blockDim.y) {
        s_w[idx] = w[c * Kh * Kw + idx];
      }
      __syncthreads();

      int out_h0 = blockIdx.y * TILE_H + threadIdx.y;
      int out_w0 = blockIdx.x * TILE_W + threadIdx.x;

      if (out_h0 < H_out && out_w0 < W_out) {
        float acc = 0.0f;
        // Compute input top-left corner for this output
        int in_h_start = out_h0 * stride_h - pad_h;
        int in_w_start = out_w0 * stride_w - pad_w;
        // Convolution sum over K
        for (int kh = 0; kh < Kh; ++kh) {
          int in_h = in_h_start + kh * dilation_h;
          if (in_h >= 0 && in_h < H) {
            for (int kw = 0; kw < Kw; ++kw) {
              int in_w = in_w_start + kw * dilation_w;
              if (in_w >= 0 && in_w < W) {
                float xv = x[((n * C + c) * H + in_h) * W + in_w];
                float wv = s_w[kh * Kw + kw];
                acc += xv * wv;
              }
            }
          }
        }
        if (b != nullptr) {
          acc += b[c];
        }
        y[((n * C + c) * H_out + out_h0) * W_out + out_w0] = acc;
      }
    }

    // Pointwise 1x1: tile spatial by TILE_HxTILE_W and compute OC_TILE output channels per block
    template<int TILE_H, int TILE_W, int OC_TILE>
    __global__ void pointwise_kernel(const float* __restrict__ x,
                                     const float* __restrict__ w, // [OC, C]
                                     const float* __restrict__ b,
                                     float* __restrict__ y,
                                     int N, int C, int H, int W, int OC) {
      extern __shared__ float s_w[]; // [OC_TILE * C]
      int tiles_h = gridDim.y;
      int tiles_w = gridDim.x;
      int num_oc_tiles = div_up(OC, OC_TILE);

      int oc_tile_idx = blockIdx.z % num_oc_tiles;
      int n = blockIdx.z / num_oc_tiles;

      int oc_base = oc_tile_idx * OC_TILE;

      // Load weights slice [OC_TILE, C] into shared memory
      for (int idx = threadIdx.y * blockDim.x + threadIdx.x; idx < OC_TILE * C; idx += blockDim.x * blockDim.y) {
        int oc_i = idx / C;
        int ic = idx - oc_i * C;
        int oc = oc_base + oc_i;
        if (oc < OC) {
          s_w[oc_i * C + ic] = w[oc * C + ic];
        }
      }
      __syncthreads();

      int h0 = blockIdx.y * TILE_H + threadIdx.y;
      int w0 = blockIdx.x * TILE_W + threadIdx.x;

      if (h0 < H && w0 < W && n < N) {
        float acc[OC_TILE];
        #pragma unroll
        for (int i = 0; i < OC_TILE; ++i) acc[i] = 0.0f;

        // Accumulate over input channels
        for (int ic = 0; ic < C; ++ic) {
          float xv = x[((n * C + ic) * H + h0) * W + w0];
          #pragma unroll
          for (int i = 0; i < OC_TILE; ++i) {
            int oc = oc_base + i;
            if (oc < OC) {
              float wv = s_w[i * C + ic];
              acc[i] += xv * wv;
            }
          }
        }
        // Add bias and store
        #pragma unroll
        for (int i = 0; i < OC_TILE; ++i) {
          int oc = oc_base + i;
          if (oc < OC) {
            float v = acc[i];
            if (b != nullptr) v += b[oc];
            y[((n * OC + oc) * H + h0) * W + w0] = v;
          }
        }
      }
    }

    // Wrapper: depthwise_forward
    torch::Tensor depthwise_forward(torch::Tensor input,
                                    torch::Tensor weight,
                                    torch::Tensor bias,
                                    int stride_h, int stride_w,
                                    int pad_h, int pad_w,
                                    int dilation_h, int dilation_w,
                                    int kernel_h, int kernel_w) {
      TORCH_CHECK(input.is_cuda(), "input must be CUDA");
      TORCH_CHECK(weight.is_cuda(), "weight must be CUDA");
      TORCH_CHECK((!bias.defined()) || bias.is_cuda(), "bias must be CUDA if defined");
      TORCH_CHECK(input.scalar_type() == at::kFloat, "only float32 supported");
      TORCH_CHECK(weight.scalar_type() == at::kFloat, "only float32 supported for weight");
      TORCH_CHECK((!bias.defined()) || bias.scalar_type() == at::kFloat, "bias must be float32");
      TORCH_CHECK(input.dim() == 4, "input must be [N,C,H,W]");
      TORCH_CHECK(weight.dim() == 4, "weight must be [C,1,Kh,Kw]");

      auto x = input.contiguous();
      auto w = weight.contiguous();
      int64_t N = x.size(0);
      int64_t C = x.size(1);
      int64_t H = x.size(2);
      int64_t W = x.size(3);
      TORCH_CHECK(w.size(0) == C && w.size(1) == 1, "weight shape must be [C,1,Kh,Kw]");
      int Kh = weight.size(2);
      int Kw = weight.size(3);
      TORCH_CHECK(Kh == kernel_h && Kw == kernel_w, "kernel size mismatch");

      if (bias.defined() && bias.numel() > 0) {
        TORCH_CHECK(bias.dim() == 1 && bias.size(0) == C, "bias must be [C]");
      }

      int H_out = (int) ((H + 2 * pad_h - dilation_h * (Kh - 1) - 1) / stride_h + 1);
      int W_out = (int) ((W + 2 * pad_w - dilation_w * (Kw - 1) - 1) / stride_w + 1);
      TORCH_CHECK(H_out >= 0 && W_out >= 0, "computed output size is negative");

      auto y = at::empty({N, C, H_out, W_out}, x.options());

      const float* x_ptr = x.data_ptr<float>();
      const float* w_ptr = w.data_ptr<float>();
      const float* b_ptr = nullptr;
      float* y_ptr = y.data_ptr<float>();
      if (bias.defined() && bias.numel() > 0) {
        bias = bias.contiguous();
        b_ptr = bias.data_ptr<float>();
      }

      dim3 block(16, 16, 1);
      dim3 grid(div_up(W_out, 16), div_up(H_out, 16), (unsigned int)(N * C));
      size_t shmem = (size_t)Kh * Kw * sizeof(float);
      auto stream = at::cuda::getCurrentCUDAStream();

      // Launch
      depthwise_kernel<16,16><<<grid, block, shmem, stream>>>(
          x_ptr, w_ptr, b_ptr, y_ptr, (int)N, (int)C, (int)H, (int)W,
          H_out, W_out, Kh, Kw, stride_h, stride_w, pad_h, pad_w, dilation_h, dilation_w);
      C10_CUDA_KERNEL_LAUNCH_CHECK();

      return y;
    }

    // Wrapper: pointwise_forward
    torch::Tensor pointwise_forward(torch::Tensor input,
                                    torch::Tensor weight,
                                    torch::Tensor bias) {
      TORCH_CHECK(input.is_cuda(), "input must be CUDA");
      TORCH_CHECK(weight.is_cuda(), "weight must be CUDA");
      TORCH_CHECK((!bias.defined()) || bias.is_cuda(), "bias must be CUDA if defined");
      TORCH_CHECK(input.scalar_type() == at::kFloat, "only float32 supported");
      TORCH_CHECK(weight.scalar_type() == at::kFloat, "only float32 supported for weight");
      TORCH_CHECK((!bias.defined()) || bias.scalar_type() == at::kFloat, "bias must be float32");
      TORCH_CHECK(input.dim() == 4, "input must be [N,C,H,W]");
      TORCH_CHECK(weight.dim() == 4, "weight must be [OC,C,1,1]");

      auto x = input.contiguous();
      auto w = weight.contiguous();

      int64_t N = x.size(0);
      int64_t C = x.size(1);
      int64_t H = x.size(2);
      int64_t W = x.size(3);
      int64_t OC = w.size(0);
      TORCH_CHECK(w.size(1) == C && w.size(2) == 1 && w.size(3) == 1, "weight must be [OC,C,1,1]");

      if (bias.defined() && bias.numel() > 0) {
        TORCH_CHECK(bias.dim() == 1 && bias.size(0) == OC, "bias must be [OC]");
      }

      auto y = at::empty({N, OC, H, W}, x.options());

      const float* x_ptr = x.data_ptr<float>();
      float* y_ptr = y.data_ptr<float>();

      // Flatten weight to [OC, C]
      auto w2 = w.view({OC, C}).contiguous();
      const float* w_ptr = w2.data_ptr<float>();

      const float* b_ptr = nullptr;
      if (bias.defined() && bias.numel() > 0) {
        bias = bias.contiguous();
        b_ptr = bias.data_ptr<float>();
      }

      // Tiling
      constexpr int TILE_H = 8;
      constexpr int TILE_W = 8;
      constexpr int OC_TILE = 8;

      dim3 block(TILE_W, TILE_H, 1);
      dim3 grid(div_up((int)W, TILE_W), div_up((int)H, TILE_H), (unsigned int)(N * div_up((int)OC, OC_TILE)));
      size_t shmem = (size_t)OC_TILE * (size_t)C * sizeof(float);
      auto stream = at::cuda::getCurrentCUDAStream();

      pointwise_kernel<TILE_H, TILE_W, OC_TILE><<<grid, block, shmem, stream>>>(
          x_ptr, w_ptr, b_ptr, y_ptr, (int)N, (int)C, (int)H, (int)W, (int)OC);
      C10_CUDA_KERNEL_LAUNCH_CHECK();
      return y;
    }
    """

    name = f"dwsep_ext_{os.getpid()}_{int(time.time())}_{uuid.uuid4().hex[:8]}"
    ext = load_inline(
        name=name,
        cpp_sources=[cpp_src],
        cuda_sources=[cuda_src],
        functions=["depthwise_forward", "pointwise_forward"],
        extra_cflags=["-O3"],
        extra_cuda_cflags=["-O3", "-use_fast_math"],
        verbose=True,
    )
    return ext


