#include <torch/extension.h>

// fused conv_transpose2d + post-processing (extra bias + clamp + scale + clamp + divide)
// Arguments:
//  - input: N x C_in x H x W (float32, CUDA, contiguous)
//  - weight: C_in x (C_out/groups) x kH x kW (float32, CUDA, contiguous)
//  - conv_bias: optional, shape (C_out) (float32, CUDA)
//  - extra_bias: (C_out, 1, 1) or (C_out) (float32, CUDA)
//  - stride, padding, output_padding: vector<int64_t> of size 2
//  - groups: int64_t
//  - scale: double (will be cast to float)
//
// Returns:
//  - output: N x C_out x H_out x W_out (float32, CUDA)
torch::Tensor fused_convtrans_post(
    torch::Tensor input,
    torch::Tensor weight,
    c10::optional<torch::Tensor> conv_bias,
    torch::Tensor extra_bias,
    std::vector<int64_t> stride,
    std::vector<int64_t> padding,
    std::vector<int64_t> output_padding,
    int64_t groups,
    double scale
);
"""

_cuda_impl = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

namespace {

__device__ __forceinline__ float clamp01(float x) {
    // clamp to [0, 1]
    return fminf(fmaxf(x, 0.0f), 1.0f);
}

__global__ void fused_post_kernel(
    const float* __restrict__ in,
    float* __restrict__ out,
    const float* __restrict__ bias, // size C
    int N, int C, int H, int W,
    float scale)
{
    int c = blockIdx.x; // [0, C)
    int n = blockIdx.y; // [0, N)
    if (c >= C || n >= N) return;

    int HW = H * W;
    size_t base = ((size_t)n * (size_t)C + (size_t)c) * (size_t)HW;
    float b = bias[c];

    for (int idx = threadIdx.x; idx < HW; idx += blockDim.x) {
        size_t off = base + (size_t)idx;
        float v = in[off];
        // v = (v + b) |> clamp01 |> (*scale) |> clamp01 |> (/scale)
        v = v + b;
        v = clamp01(v);
        v = v * scale;
        v = clamp01(v);
        v = v / scale;
        out[off] = v;
    }
}

} // namespace

torch::Tensor fused_convtrans_post(
    torch::Tensor input,
    torch::Tensor weight,
    c10::optional<torch::Tensor> conv_bias,
    torch::Tensor extra_bias,
    std::vector<int64_t> stride,
    std::vector<int64_t> padding,
    std::vector<int64_t> output_padding,
    int64_t groups,
    double scale_double)
