    TORCH_CHECK(weight.scalar_type() == at::kFloat, "weight must be float32");
    TORCH_CHECK(input.dim() == 4, "input must be 4D NCHW");
    TORCH_CHECK(weight.dim() == 4, "weight must be 4D (C_in, C_out/groups, kH, kW)");
    TORCH_CHECK(stride.size() == 2 && padding.size() == 2 && output_padding.size() == 2, "stride/padding/output_padding must have 2 elements");
    TORCH_CHECK(groups >= 1, "groups must be >= 1");

