    TORCH_CHECK(extra_bias.scalar_type() == at::kFloat, "extra_bias must be float32");
    TORCH_CHECK(extra_bias.dim() == 1 || (extra_bias.dim() == 3 && extra_bias.size(1) == 1 && extra_bias.size(2) == 1),
