    auto y_c = y.contiguous();
    auto out = at::empty_like(y_c);

    int N = static_cast<int>(y_c.size(0));
    int C = static_cast<int>(y_c.size(1));
    int H = static_cast<int>(y_c.size(2));
    int W = static_cast<int>(y_c.size(3));

    const float* in_ptr = y_c.data_ptr<float>();
    const float* b_ptr  = bias_c.data_ptr<float>();
    float* out_ptr = out.data_ptr<float>();

    dim3 block(256, 1, 1);
    dim3 grid(C, N, 1); // one block per (c, n)
