                                  const float* __restrict__ Wsum,
                                  const float* __restrict__ bias,
                                  float* __restrict__ Y,
                                  int B, int K, int O) {
    int tid = threadIdx.x;

    // Shared memory for reductions
    __shared__ float sdata[TPB];
    __shared__ float b_total_shared;

    // Compute total bias once per block (on device, no host sync)
    float bsum = 0.f;
    for (int o = tid; o < O; o += TPB) {
        bsum += bias[o];
    }
    sdata[tid] = bsum;
    __syncthreads();
    // Reduce bias sum to a single value
    for (int s = TPB >> 1; s > 0; s >>= 1) {
        if (tid < s) {
            sdata[tid] += sdata[tid + s];
        }
        __syncthreads();
    }
    if (tid == 0) {
        b_total_shared = sdata[0];
    }
    __syncthreads();

    // Each block processes multiple rows striding by gridDim.x
    for (int row = blockIdx.x; row < B; row += gridDim.x) {
        float sum = 0.f;
        int base = row * K;
        // Each thread accumulates a strided subset for coalesced access
        for (int k = tid; k < K; k += TPB) {
            sum += X[base + k] * Wsum[k];
        }
        sdata[tid] = sum;
        __syncthreads();
        // Parallel reduction within the block to get the dot product
        for (int s = TPB >> 1; s > 0; s >>= 1) {
            if (tid < s) {
                sdata[tid] += sdata[tid + s];
            }
            __syncthreads();
        }
        if (tid == 0) {
            // Final output equals sum over outputs of the linear layer:
            // sum_o (X_row · W[o,:] + b[o]) = (X_row · sum_o W[o,:]) + sum_o b[o]
            Y[row] = sdata[0] + b_total_shared;
        }
        __syncthreads();
    }
}

torch::Tensor fused_linear_sum(torch::Tensor input, torch::Tensor weight, torch::Tensor bias) {
    TORCH_CHECK(input.is_cuda(), "input must be a CUDA tensor");
    TORCH_CHECK(weight.is_cuda(), "weight must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
    TORCH_CHECK(input.dtype() == torch::kFloat32, "input must be float32");
    TORCH_CHECK(weight.dtype() == torch::kFloat32, "weight must be float32");
    TORCH_CHECK(bias.dtype() == torch::kFloat32, "bias must be float32");
    TORCH_CHECK(input.dim() == 2, "input must be 2D [B, K]");
    TORCH_CHECK(weight.dim() == 2, "weight must be 2D [O, K]");
    TORCH_CHECK(bias.dim() == 1, "bias must be 1D [O]");
    TORCH_CHECK(weight.size(1) == input.size(1), "weight.size(1) must equal input.size(1)");
    TORCH_CHECK(weight.size(0) == bias.size(0), "weight.size(0) must equal bias.size(0)");
    TORCH_CHECK(input.device().index() == weight.device().index() && input.device().index() == bias.device().index(),
                "All tensors must be on the same CUDA device");

    const int64_t B64 = input.size(0);
    const int64_t K64 = input.size(1);
    const int64_t O64 = weight.size(0);
    TORCH_CHECK(B64 >= 0 && K64 >= 0 && O64 >= 0, "Invalid sizes");

    // Make contiguous before raw pointer access
    auto input_c = input.contiguous();
    auto weight_c = weight.contiguous();
    auto bias_c = bias.contiguous();

    // Compute aggregated weights on device (no host sync)
    auto w_sum = weight_c.sum(0).contiguous(); // [K]

    // Allocate output [B, 1]
    auto out = torch::empty({B64, 1}, input_c.options());

    const int B = static_cast<int>(B64);
    const int K = static_cast<int>(K64);
    const int O = static_cast<int>(O64);

    const int threads = 256;
    int blocks = B;
    if (blocks <= 0) blocks = 1;
    if (blocks > 65535) blocks = 65535;

    auto stream = at::cuda::getCurrentCUDAStream();

    fused_gemv_kernel<256><<<blocks, threads, 0, stream>>>(
        input_c.data_ptr<float>(),
        w_sum.data_ptr<float>(),
        bias_c.data_ptr<float>(),
        out.data_ptr<float>(),
        B, K, O
    );

    return out;
}
""",
