    cuda_sources = r"""
    #include <torch/extension.h>
    #include <cuda_runtime.h>
    #include <ATen/cuda/CUDAContext.h>

    __global__ void mean_reduce_kernel(const float* __restrict__ in,
                                       float* __restrict__ out,
                                       long long inner) {
        // One block per batch element; gridDim.x == N
        int b = blockIdx.x;
        int tid = threadIdx.x;
        extern __shared__ float sdata[];
        long long base = (long long)b * inner;

        float thread_sum = 0.0f;

        // Loop over inner dimension with a stride of blockDim.x
        for (long long idx = tid; idx < inner; idx += blockDim.x) {
            thread_sum += in[base + idx];
        }

        // Block reduction in shared memory
        sdata[tid] = thread_sum;
        __syncthreads();

        // Reduce in shared memory down to 32 values
        for (unsigned int s = blockDim.x >> 1; s > 32; s >>= 1) {
            if (tid < s) {
                sdata[tid] += sdata[tid + s];
            }
            __syncthreads();
        }

        // Warp-level reduction
        float val = sdata[tid];
        if (tid < 32) {
            // If we didn't perform the s==32 step in shared mem, fold it in here
            if (blockDim.x >= 64) {
                val += sdata[tid + 32];
            }
            #pragma unroll
            for (int offset = 16; offset > 0; offset >>= 1) {
                val += __shfl_down_sync(0xffffffff, val, offset);
            }
            if (tid == 0) {
                out[b] = val / (float)inner;
            }
        }
    }

