import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline

# CUDA/C++ extension sources
cpp_src = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

void launch_instancenorm_reduce_kernel(const float* x, float* mean, float* var,
                                       int N, int C, int inner, float eps, cudaStream_t stream);
void launch_instancenorm_apply_fused_kernel(const float* x, const float* mean, const float* var,
                                            const float* residual, float* y,
                                            int N, int C, int inner, float eps, cudaStream_t stream);

// Fused path: compute per-(N,C) statistics over 'inner' dimension (InstanceNorm-like with C=1 for our use),
// then apply normalization and fuse residual add and multiply:
// out = ((x - mean) * rsqrt(var + eps) + residual) * residual
torch::Tensor fused_inorm_rowwise_add_mul(torch::Tensor x, torch::Tensor residual, double eps) {
  TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
  TORCH_CHECK(residual.is_cuda(), "residual must be a CUDA tensor");
  TORCH_CHECK(x.is_contiguous(), "x must be contiguous");
  TORCH_CHECK(residual.is_contiguous(), "residual must be contiguous");
  TORCH_CHECK(x.scalar_type() == at::kFloat, "x must be float32 (cast before calling)");
  TORCH_CHECK(residual.scalar_type() == at::kFloat, "residual must be float32 (cast before calling)");
  TORCH_CHECK(x.sizes() == residual.sizes(), "x and residual must have the same shape");

  int64_t N = x.size(0);
  TORCH_CHECK(x.dim() == 2, "x must be 2D [N, F] for row-wise instance normalization");
  int64_t inner = x.size(1);
  int C = 1; // row-wise normalization across features

  auto options = x.options();
  auto mean = at::empty({N * C}, options);
  auto var  = at::empty({N * C}, options);
  auto out  = at::empty_like(x);

  cudaStream_t stream = at::cuda::getCurrentCUDAStream();
  launch_instancenorm_reduce_kernel(
      x.data_ptr<float>(), mean.data_ptr<float>(), var.data_ptr<float>(),
      static_cast<int>(N), C, static_cast<int>(inner),
      static_cast<float>(eps), stream);

  launch_instancenorm_apply_fused_kernel(
      x.data_ptr<float>(), mean.data_ptr<float>(), var.data_ptr<float>(),
      residual.data_ptr<float>(), out.data_ptr<float>(),
      static_cast<int>(N), C, static_cast<int>(inner),
      static_cast<float>(eps), stream);

  return out;
}
"""

cuda_src = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#ifndef CHECK_CUDA
#define CHECK_CUDA(x) TORCH_CHECK(x.is_cuda(), #x " must be CUDA tensor")
#endif

// Reduction kernel: compute mean and variance per (N,C) over 'inner' elements.
// x is logically [N, C, inner], but we pass a contiguous [N, inner] and use C=1.
__global__ void instancenorm_reduce_kernel(const float* __restrict__ x,
                                           float* __restrict__ mean,
                                           float* __restrict__ var,
                                           int N, int C, int inner) {
  // One block per (n,c)
  int nc = blockIdx.x; // 0..N*C-1
  int tid = threadIdx.x;

  const int threads = blockDim.x;
  // Base pointer for this (n,c)
  int64_t offset = static_cast<int64_t>(nc) * inner;

  float sum = 0.0f;
  float sumsq = 0.0f;

  for (int i = tid; i < inner; i += threads) {
    float v = x[offset + i];
    sum += v;
    sumsq += v * v;
  }

  __shared__ float ssum[256];
  __shared__ float ssum2[256];
  ssum[tid] = sum;
  ssum2[tid] = sumsq;
  __syncthreads();

  // Tree reduction
  for (int stride = threads >> 1; stride > 0; stride >>= 1) {
    if (tid < stride) {
      ssum[tid] += ssum[tid + stride];
      ssum2[tid] += ssum2[tid + stride];
    }
    __syncthreads();
  }

  if (tid == 0) {
    float m = ssum[0] / static_cast<float>(inner);
    float e2 = ssum2[0] / static_cast<float>(inner);
    float v = e2 - m * m;
    if (v < 0.f) v = 0.f; // numerical guard
    mean[nc] = m;
    var[nc] = v;
  }
}

// Apply normalization and fuse residual add/mul:
// For each element t corresponding to (nc, i) where nc = t / inner, i = t % inner:
// norm = (x[t] - mean[nc]) * rsqrt(var[nc] + eps);
// y[t] = (norm + residual[t]) * residual[t];
__global__ void instancenorm_apply_fused_kernel(const float* __restrict__ x,
                                                const float* __restrict__ mean,
                                                const float* __restrict__ var,
                                                const float* __restrict__ residual,
                                                float* __restrict__ y,
                                                int N, int C, int inner,
                                                float eps) {
  int64_t total = static_cast<int64_t>(N) * C * inner;
  int64_t t = static_cast<int64_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  if (t >= total) return;
  int nc = static_cast<int>(t / inner);
  float m = mean[nc];
  float v = var[nc];
  float inv_std = rsqrtf(v + eps);
  float xn = (x[t] - m) * inv_std;
  float r = residual[t];
  y[t] = (xn + r) * r;
}

void launch_instancenorm_reduce_kernel(const float* x, float* mean, float* var,
                                       int N, int C, int inner, float eps, cudaStream_t stream) {
  int blocks = N * C;
  int threads = 256;
  instancenorm_reduce_kernel<<<blocks, threads, 0, stream>>>(x, mean, var, N, C, inner);
}

void launch_instancenorm_apply_fused_kernel(const float* x, const float* mean, const float* var,
                                            const float* residual, float* y,
                                            int N, int C, int inner, float eps,
                                            cudaStream_t stream) {
  int64_t total = static_cast<int64_t>(N) * C * inner;
  int threads = 256;
  int blocks = static_cast<int>((total + threads - 1) / threads);
  instancenorm_apply_fused_kernel<<<blocks, threads, 0, stream>>>(x, mean, var, residual, y, N, C, inner, eps);
}
"""

# Build extension at import time
_custom_ext = load_inline(
    name="custom_kernels_ext",
    cpp_sources=[cpp_src],
    cuda_sources=[cuda_src],
    functions=["fused_inorm_rowwise_add_mul"],
    with_cuda=True,
    extra_cflags=['-O3'],
    extra_cuda_cflags=['-O3', '--use_fast_math'],
    verbose=False,
)

class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that accelerates the instance normalization and subsequent
    add/mul sequence using custom CUDA kernels. The API and signatures are preserved.
    """
    def __init__(self, in_features, out_features, eps=1e-5, momentum=0.1):
