        # Keep attributes for API parity; InstanceNorm module is not used in forward.
        self.instance_norm = nn.InstanceNorm2d(out_features, eps=eps, momentum=momentum)
        self._eps = float(eps)

    def forward(self, x, y):
        """
        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_features).
            y (torch.Tensor): Input tensor of shape (batch_size, out_features).
        Returns:
            torch.Tensor: Output tensor of shape (batch_size, out_features).
        """
        x = self.bmm(x)

        # Custom fused row-wise instance normalization + residual add/mul.
        # Cast to float32 for deterministic parity in custom kernels.
        orig_dtype = x.dtype
        x32 = x.to(torch.float32).contiguous()
        y32 = y.to(torch.float32).contiguous()
        # Ensure tensors are on CUDA
        if not x32.is_cuda:
            x32 = x32.cuda()
        if not y32.is_cuda:
            y32 = y32.cuda()

        out32 = _custom_ext.fused_inorm_rowwise_add_mul(x32, y32, self._eps)

        return out32.to(orig_dtype)

# For local testing convenience (optional)
if __name__ == "__main__":
