#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>
#include <float.h>

__global__ void lse_channel_kernel_1tps(const float* __restrict__ in,
                                        float* __restrict__ out,
                                        int N, int C, int D, int H, int W) {
    const int64_t nSites = (int64_t)N * D * H * W;
    int64_t site = (int64_t)blockIdx.x * blockDim.x + threadIdx.x;
    if (site >= nSites) return;

    // Decompose site -> (n, d, h, w)
    int64_t tmp = site;
    int w = (int)(tmp % W); tmp /= W;
    int h = (int)(tmp % H); tmp /= H;
    int d = (int)(tmp % D); tmp /= D;
    int n = (int)tmp;

    // Stride for channel in contiguous [N,C,D,H,W]
    const int64_t stride_c = (int64_t)D * H * W;

    // Base index for input at c=0 for this (n,d,h,w)
    int64_t base_in = (((int64_t)n * C) * D + d) * H + h;
    base_in = base_in * W + w; // index for (n, c=0, d, h, w)

    // Compute max over C
    float m = in[base_in];
    for (int c = 1; c < C; ++c) {
        float v = in[base_in + (int64_t)c * stride_c];
        m = v > m ? v : m;
    }

    // Compute sum of exp(x - m)
    float s = 0.0f;
    for (int c = 0; c < C; ++c) {
        float v = in[base_in + (int64_t)c * stride_c];
        s += __expf(v - m);
    }

    float outv = __logf(s) + m;

    // Output index for [N,1,D,H,W] at (n,0,d,h,w)
    int64_t out_idx = (((int64_t)n * D + d) * H + h) * W + w;
    out[out_idx] = outv;
}

void launch_logsumexp_channel(const float* in, float* out,
                              int N, int C, int D, int H, int W,
                              cudaStream_t stream) {
    const int64_t nSites = (int64_t)N * D * H * W;
    const int threads = 256;
    const int blocks = (int)((nSites + threads - 1) / threads);
    lse_channel_kernel_1tps<<<blocks, threads, 0, stream>>>(in, out, N, C, D, H, W);
}
