    """
    Drop-in replacement for Model with a custom CUDA kernel accelerating
    the logsumexp reduction over the channel dimension after pooling.
    API is identical to Model.
    """
    def __init__(self, in_channels, out_channels, kernel_size, stride, padding):
        super(ModelNew, self).__init__()
        self.conv = nn.Conv3d(in_channels, out_channels, kernel_size, stride=stride, padding=padding)
        self.max_pool = nn.MaxPool3d(kernel_size=2, stride=2)

    def forward(self, x):
        """
        Args:
            x: Input tensor of shape (batch_size, in_channels, depth, height, width)
        Returns:
            Output tensor of shape (batch_size, 1, depth', height', width')
        """
        x = self.conv(x)
        x = self.max_pool(x)

        # Use custom CUDA kernel only for float32 tensors on CUDA for exact parity.
        if x.is_cuda and _ext is not None and x.dtype == torch.float32:
            lse = _ext.lse_channel_forward(x.contiguous())
        else:
            # Fallback: preserve dtype and device semantics
            lse = torch.logsumexp(x, dim=1, keepdim=True)

        x = torch.relu(lse)
        return x

