import math
import types
import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline

# Global extension handle (built once)
_EXT_HANDLE = None

def _build_extension():
    global _EXT_HANDLE
    if _EXT_HANDLE is not None:
        return _EXT_HANDLE

    cpp_src = r"""
    #include <torch/extension.h>
    // Declarations only
    torch::Tensor gemm_bias_forward(torch::Tensor A, torch::Tensor B, torch::Tensor bias);
    torch::Tensor gemm_bias_relu_forward(torch::Tensor A, torch::Tensor B, torch::Tensor bias);
    """

    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    __global__ void bias_add_kernel(const float* __restrict__ bias,
                                    float* __restrict__ C,
                                    int64_t M, int64_t N) {
      int64_t idx = blockIdx.x * (int64_t)blockDim.x + threadIdx.x;
      int64_t total = M * N;
      for (int64_t i = idx; i < total; i += (int64_t)blockDim.x * gridDim.x) {
        int64_t j = i % N;
        C[i] = C[i] + bias[j];
      }
    }

    __global__ void bias_relu_kernel(const float* __restrict__ bias,
                                     float* __restrict__ C,
                                     int64_t M, int64_t N) {
      int64_t idx = blockIdx.x * (int64_t)blockDim.x + threadIdx.x;
      int64_t total = M * N;
      for (int64_t i = idx; i < total; i += (int64_t)blockDim.x * gridDim.x) {
        int64_t j = i % N;
        float v = C[i] + bias[j];
        C[i] = v > 0.f ? v : 0.f;
      }
    }

    static inline void launch_bias_add(torch::Tensor& C, const torch::Tensor& bias) {
      int64_t M = C.size(0);
      int64_t N = C.size(1);
      if (M == 0 || N == 0) return;
      cudaStream_t stream = at::cuda::getCurrentCUDAStream();
      int threads = 256;
      int64_t total = M * N;
      int blocks = (int)((total + threads - 1) / threads);
      blocks = blocks < 1 ? 1 : blocks;
      if (blocks > 1048576) blocks = 1048576;
      bias_add_kernel<<<blocks, threads, 0, stream>>>(
        bias.data_ptr<float>(),
        C.data_ptr<float>(),
        M, N
      );
      cudaError_t err = cudaGetLastError();
      TORCH_CHECK(err == cudaSuccess, "bias_add_kernel launch failed: ", cudaGetErrorString(err));
    }

    static inline void launch_bias_relu(torch::Tensor& C, const torch::Tensor& bias) {
      int64_t M = C.size(0);
      int64_t N = C.size(1);
      if (M == 0 || N == 0) return;
      cudaStream_t stream = at::cuda::getCurrentCUDAStream();
      int threads = 256;
      int64_t total = M * N;
      int blocks = (int)((total + threads - 1) / threads);
      blocks = blocks < 1 ? 1 : blocks;
      if (blocks > 1048576) blocks = 1048576;
      bias_relu_kernel<<<blocks, threads, 0, stream>>>(
        bias.data_ptr<float>(),
        C.data_ptr<float>(),
        M, N
      );
      cudaError_t err = cudaGetLastError();
      TORCH_CHECK(err == cudaSuccess, "bias_relu_kernel launch failed: ", cudaGetErrorString(err));
    }

    static inline void validate_gemm_inputs(const torch::Tensor& A,
                                            const torch::Tensor& B,
                                            const torch::Tensor& bias) {
      TORCH_CHECK(A.is_cuda() && B.is_cuda() && bias.is_cuda(), "All tensors must be CUDA");
      TORCH_CHECK(A.dim() == 2 && B.dim() == 2 && bias.dim() == 1, "Expected A/B 2D and bias 1D");
      TORCH_CHECK(A.scalar_type() == at::kFloat && B.scalar_type() == at::kFloat && bias.scalar_type() == at::kFloat,
                  "Only float32 supported");
      TORCH_CHECK(A.size(1) == B.size(0), "GEMM inner dims must match: A[M,K], B[K,N]");
      TORCH_CHECK(B.size(1) == bias.size(0), "Bias must match N dimension of output");
    }

    torch::Tensor gemm_bias_forward(torch::Tensor A, torch::Tensor B, torch::Tensor bias) {
      validate_gemm_inputs(A, B, bias);
      auto A_ = A.is_contiguous() ? A : A.contiguous();
      auto B_ = B.is_contiguous() ? B : B.contiguous();
      auto bias_ = bias.is_contiguous() ? bias : bias.contiguous();
      auto C = at::matmul(A_, B_); // [M,N]
      launch_bias_add(C, bias_);
      return C;
    }

    torch::Tensor gemm_bias_relu_forward(torch::Tensor A, torch::Tensor B, torch::Tensor bias) {
      validate_gemm_inputs(A, B, bias);
      auto A_ = A.is_contiguous() ? A : A.contiguous();
      auto B_ = B.is_contiguous() ? B : B.contiguous();
      auto bias_ = bias.is_contiguous() ? bias : bias.contiguous();
      auto C = at::matmul(A_, B_); // [M,N]
      launch_bias_relu(C, bias_);
      return C;
    }
    """

    try:
        _EXT_HANDLE = load_inline(
            name="fused_linear_bias_relu_ext_v1",
            cpp_sources=[cpp_src],
            cuda_sources=[cuda_src],
            functions=["gemm_bias_forward", "gemm_bias_relu_forward"],
            extra_cflags=["-O3"],
            extra_cuda_cflags=["-O3"],
            verbose=False,
        )
    except Exception:
        _EXT_HANDLE = None
    return _EXT_HANDLE

# Autograd-compatible fused ops using the extension in forward and PyTorch ops in backward
class _FusedLinearBiasFn(torch.autograd.Function):
    @staticmethod
    def forward(ctx, x, weight, bias, weight_t, use_relu: bool):
        # x: [M,K], weight: [N,K] as in nn.Linear.weight, bias: [N], weight_t: [K,N]
        ext = _build_extension()
        if ext is None:
            # Fallback to PyTorch
            y = x.matmul(weight.t())
            y = y + bias
            if use_relu:
                y = F.relu(y)
            ctx.save_for_backward(x, weight, None if not use_relu else y)
            ctx.use_relu = use_relu
            ctx.fallback = True
            return y

        # Run accelerated forward without building autograd graph internally
        with torch.no_grad():
            if use_relu:
                y = ext.gemm_bias_relu_forward(x, weight_t, bias)
            else:
                y = ext.gemm_bias_forward(x, weight_t, bias)

        # Save for backward
        ctx.save_for_backward(x, weight, None if not use_relu else y)
        ctx.use_relu = use_relu
        ctx.fallback = False
        return y

    @staticmethod
    def backward(ctx, grad_out):
        x, weight, y = ctx.saved_tensors
        use_relu = ctx.use_relu

        # Apply ReLU mask if needed
        if use_relu:
            mask = y > 0
            grad_pre = grad_out * mask
        else:
            grad_pre = grad_out

        grad_x = grad_weight = grad_bias = None

        if ctx.needs_input_grad[0]:
            grad_x = grad_pre.matmul(weight)
        if ctx.needs_input_grad[1]:
            grad_weight = grad_pre.t().matmul(x)
        if ctx.needs_input_grad[2]:
            grad_bias = grad_pre.sum(dim=0)

        # No grad for weight_t (arg 3) and use_relu (arg 4)
        return grad_x, grad_weight, grad_bias, None, None

def _ensure_weight_t(linear: nn.Linear):
    # Lazily cache transposed weights on the same device/dtype
    current_version = getattr(linear.weight, "_version", 0)
    cached = getattr(linear, "_weight_t_cache", None)
    cached_version = getattr(linear, "_weight_t_version", -1)
    need_rebuild = (
        cached is None
        or cached_version != current_version
        or cached.shape[0] != linear.weight.shape[1]
        or cached.shape[1] != linear.weight.shape[0]
        or cached.dtype != linear.weight.dtype
        or cached.device != linear.weight.device
    )
    if need_rebuild:
        wt = linear.weight.detach().t().contiguous()
        # Keep on the same device; detach ensures no grad history
        if wt.device != linear.weight.device:
            wt = wt.to(linear.weight.device)
        # Register once as a buffer name if not present, else just assign
        if not hasattr(linear, "_weight_t_cache"):
            linear.register_buffer("_weight_t_cache", wt)
        else:
            linear._weight_t_cache = wt
        linear._weight_t_version = current_version
    return linear._weight_t_cache

def fused_linear_bias(x, linear: nn.Linear):
    wt = _ensure_weight_t(linear)
    return _FusedLinearBiasFn.apply(x, linear.weight, linear.bias, wt, False)

def fused_linear_bias_relu(x, linear: nn.Linear):
    wt = _ensure_weight_t(linear)
    return _FusedLinearBiasFn.apply(x, linear.weight, linear.bias, wt, True)

class ModelNew(nn.Module):
    def __init__(self, input_size, layer_sizes, output_size):
        """
        :param input_size: The number of input features
        :param layer_sizes: A list of ints containing the sizes of each hidden layer
        :param output_size: The number of output features
        """
        super(ModelNew, self).__init__()
        layers = []
        current_input_size = input_size
        for layer_size in layer_sizes:
            layers.append(nn.Linear(current_input_size, layer_size))
            layers.append(nn.ReLU())
            current_input_size = layer_size
        layers.append(nn.Linear(current_input_size, output_size))
        self.network = nn.Sequential(*layers)

        # Try to build the extension once; if it fails, we fall back
        self.use_ext = _build_extension() is not None

        # Precompute and register transposed weights as buffers to avoid per-forward transposes
        for m in self.network.modules():
            if isinstance(m, nn.Linear) and m.bias is not None:
                _ensure_weight_t(m)

    def forward(self, x):
        """
        :param x: The input tensor, shape (batch_size, input_size)
        :return: The output tensor, shape (batch_size, output_size)
        """
        out = x
        i = 0
        modules = list(self.network)
        while i < len(modules):
            m = modules[i]
            # Pattern: Linear followed by ReLU -> fuse
            if (
                self.use_ext
                and isinstance(m, nn.Linear)
                and i + 1 < len(modules)
                and isinstance(modules[i + 1], nn.ReLU)
                and out.is_cuda
                and out.dtype == torch.float32
                and m.bias is not None
            ):
                wt = _ensure_weight_t(m)
                out = _FusedLinearBiasFn.apply(out, m.weight, m.bias, wt, True)
                i += 2
                continue

            # Last Linear (no activation) -> fuse bias add
            if (
                self.use_ext
                and isinstance(m, nn.Linear)
                and (i + 1 == len(modules) or not isinstance(modules[i + 1], nn.ReLU))
                and out.is_cuda
                and out.dtype == torch.float32
                and m.bias is not None
            ):
                wt = _ensure_weight_t(m)
                out = _FusedLinearBiasFn.apply(out, m.weight, m.bias, wt, False)
                i += 1
                continue

            # Fallback path
            out = m(out)
            i += 1
        return out

