from torch.utils.cpp_extension import load_inline

_MAXPOOL2D_EXT = None
_MAXPOOL2D_EXT_BUILT = False

def _build_maxpool2d_ext():
    global _MAXPOOL2D_EXT, _MAXPOOL2D_EXT_BUILT
    if _MAXPOOL2D_EXT_BUILT:
        return _MAXPOOL2D_EXT
    cpp_src = r"""
    #include <torch/extension.h>

    torch::Tensor maxpool2d_forward(torch::Tensor input,
                                    int64_t kH, int64_t kW,
                                    int64_t sH, int64_t sW,
                                    int64_t pH, int64_t pW);
    """
    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    __global__ void maxpool2d_forward_kernel(const float* __restrict__ input,
                                             float* __restrict__ output,
                                             int64_t N, int64_t C, int64_t H, int64_t W,
                                             int64_t H_out, int64_t W_out,
                                             int64_t kH, int64_t kW,
                                             int64_t sH, int64_t sW,
                                             int64_t pH, int64_t pW) {
        int64_t total = N * C * H_out * W_out;
        int64_t tid = blockIdx.x * blockDim.x + threadIdx.x;
        int64_t stride = blockDim.x * gridDim.x;

        for (int64_t idx = tid; idx < total; idx += stride) {
            int64_t w_out = idx % W_out;
            int64_t tmp = idx / W_out;
            int64_t h_out = tmp % H_out;
            tmp = tmp / H_out;
            int64_t c = tmp % C;
            int64_t n = tmp / C;

            int64_t h_start = h_out * sH - pH;
            int64_t w_start = w_out * sW - pW;

            float max_val = -CUDART_INF_F;
            int64_t base_in = ((n * C + c) * H) * W;

            for (int64_t kh = 0; kh < kH; ++kh) {
                int64_t h = h_start + kh;
                if (h < 0 || h >= H) continue;
                for (int64_t kw = 0; kw < kW; ++kw) {
                    int64_t w = w_start + kw;
                    if (w < 0 || w >= W) continue;
                    float v = input[base_in + h * W + w];
                    max_val = v > max_val ? v : max_val;
                }
            }
            output[idx] = max_val;
        }
    }

    torch::Tensor maxpool2d_forward(torch::Tensor input,
                                    int64_t kH, int64_t kW,
                                    int64_t sH, int64_t sW,
                                    int64_t pH, int64_t pW) {
        TORCH_CHECK(input.is_cuda(), "maxpool2d_forward: input must be a CUDA tensor");
        TORCH_CHECK(input.scalar_type() == at::kFloat, "maxpool2d_forward: only float32 supported");
        TORCH_CHECK(input.dim() == 4, "maxpool2d_forward: input must be 4D NCHW");
        TORCH_CHECK(kH > 0 && kW > 0, "maxpool2d_forward: kernel sizes must be > 0");
        TORCH_CHECK(sH > 0 && sW > 0, "maxpool2d_forward: strides must be > 0");
        TORCH_CHECK(pH >= 0 && pW >= 0, "maxpool2d_forward: paddings must be >= 0");

        auto input_ = input.is_contiguous() ? input : input.contiguous();

        int64_t N = input_.size(0);
        int64_t C = input_.size(1);
        int64_t H = input_.size(2);
        int64_t W = input_.size(3);

        int64_t H_out = (H + 2 * pH - kH) / sH + 1;
        int64_t W_out = (W + 2 * pW - kW) / sW + 1;
        TORCH_CHECK(H_out >= 1 && W_out >= 1, "maxpool2d_forward: invalid output size");

        auto output = torch::empty({N, C, H_out, W_out}, input_.options());

        const float* in_ptr = input_.data_ptr<float>();
        float* out_ptr = output.data_ptr<float>();

        const int threads = 256;
        int64_t total = N * C * H_out * W_out;
        int blocks = (int)((total + threads - 1) / threads);
        blocks = blocks > 131072 ? 131072 : blocks;

        cudaStream_t stream = at::cuda::getCurrentCUDAStream();

        maxpool2d_forward_kernel<<<blocks, threads, 0, stream>>>(
            in_ptr, out_ptr,
            N, C, H, W, H_out, W_out,
            kH, kW, sH, sW, pH, pW
        );

        return output;
    }
    """
    try:
        ext = load_inline(
            name="maxpool2d_fwd_ext_v1",
            cpp_sources=[cpp_src],
            cuda_sources=[cuda_src],
            functions=["maxpool2d_forward"],
            extra_cflags=["-O3"],
            extra_cuda_cflags=["-O3"],
            verbose=True,
        )
        _MAXPOOL2D_EXT = ext
    except Exception as e:
        print("MaxPool2d CUDA extension build failed; falling back to PyTorch ops. Error:", e)
        _MAXPOOL2D_EXT = None
    _MAXPOOL2D_EXT_BUILT = True
    return _MAXPOOL2D_EXT


