    float local_max = -FLT_MAX;
    for (int j = tid; j < row_len; j += blockDim.x) {
        if (j <= i) {
            float val = S[base + j] * scale;
            local_max = fmaxf(local_max, val);
        }
    }
    extern __shared__ float sdata[];
    sdata[tid] = local_max;
    __syncthreads();

    // parallel reduction for max
    for (int offset = blockDim.x >> 1; offset > 0; offset >>= 1) {
        if (tid < offset) {
            sdata[tid] = fmaxf(sdata[tid], sdata[tid + offset]);
        }
        __syncthreads();
    }
    float row_max = sdata[0];

    // 2) Compute sum of exp(x - max), and store unnormalized exp in S for j <= i; set 0 for j > i
    float local_sum = 0.0f;
    for (int j = tid; j < row_len; j += blockDim.x) {
        float out = 0.0f;
        if (j <= i) {
            float val = S[base + j] * scale;
            float ex = __expf(val - row_max);
            out = ex;
            local_sum += ex;
        }
        S[base + j] = out;
    }
    __syncthreads();

    sdata[tid] = local_sum;
    __syncthreads();

    // reduction for sum
    for (int offset = blockDim.x >> 1; offset > 0; offset >>= 1) {
        if (tid < offset) {
            sdata[tid] += sdata[tid + offset];
        }
        __syncthreads();
    }
    float denom = sdata[0] + 1e-20f; // avoid div-by-zero

    // 3) Normalize
    for (int j = tid; j < row_len; j += blockDim.x) {
        if (j <= i) {
            S[base + j] = S[base + j] / denom;
        } else {
            // ensure masked positions are exactly zero
            S[base + j] = 0.0f;
        }
    }
}

// q: [B, H, T, D], k: [B, H, T, D]
// Returns attn probabilities: [B, H, T, T]
// Computes scores = q @ k^T, scales by `scale`, applies causal mask and softmax along last dim.
torch::Tensor attn_scores_masked_softmax(torch::Tensor q, torch::Tensor k, double scale_d) {
    CHECK_CUDA(q);
    CHECK_CUDA(k);
    CHECK_FLOAT(q);
    CHECK_FLOAT(k);
    CHECK_DIM(q, 4);
    CHECK_DIM(k, 4);
    TORCH_CHECK(q.sizes() == k.sizes(), "q and k must have the same shape");

    auto B = (int)q.size(0);
    auto H = (int)q.size(1);
    auto T = (int)q.size(2);
    auto D = (int)q.size(3);
    TORCH_CHECK(T >= 1 && D >= 1, "Invalid shapes for q,k");

    auto q_c = q.contiguous();
    auto k_c = k.contiguous();

    // Flatten heads into batch for bmm
    auto BH = B * H;
    auto q2 = q_c.view({BH, T, D});
    auto k2 = k_c.view({BH, T, D});
    auto kt = k2.transpose(1, 2).contiguous(); // [BH, D, T]

    // Scores: [BH, T, T]
    auto scores2 = at::bmm(q2, kt);

    // Reshape to [B, H, T, T] and ensure contiguous for kernel
    auto scores = scores2.view({B, H, T, T}).contiguous();

    float scale = static_cast<float>(scale_d);

    // Launch kernel to apply causal masked softmax in-place
    dim3 block(128);
    dim3 grid(T, H, B);
    size_t shmem = block.x * sizeof(float);
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    causal_masked_softmax_kernel<<<grid, block, shmem, stream>>>(
        scores.data_ptr<float>(), B, H, T, scale
    );

    return scores;
}

// attn: [B, H, T, T], v: [B, H, T, D]
// Returns y: [B, H, T, D] = attn @ v
torch::Tensor bmm_att_v(torch::Tensor attn, torch::Tensor v) {
    CHECK_CUDA(attn);
    CHECK_CUDA(v);
    CHECK_FLOAT(attn);
    CHECK_FLOAT(v);
    CHECK_DIM(attn, 4);
    CHECK_DIM(v, 4);

    auto B = (int)attn.size(0);
    auto H = (int)attn.size(1);
    auto T = (int)attn.size(2);
    TORCH_CHECK(attn.size(3) == T, "attn must be square on the last two dims");
    TORCH_CHECK(v.size(0) == B && v.size(1) == H && v.size(2) == T, "v must match [B,H,T,D]");
    auto D = (int)v.size(3);

    auto attn_c = attn.contiguous();
    auto v_c = v.contiguous();

    auto BH = B * H;
    auto a2 = attn_c.view({BH, T, T});
    auto v2 = v_c.view({BH, T, D});

    auto y2 = at::bmm(a2, v2); // [BH, T, D]
    auto y = y2.view({B, H, T, D});
    return y;
}
"""

_kb_ext = None
def _build_kb_ext():
    global _kb_ext
    if _kb_ext is not None:
        return _kb_ext
    try:
        _kb_ext = load_inline(
            name="kb_ext",
            cpp_sources=[_CPP_SOURCES],
            cuda_sources=[_CUDA_SOURCES],
            functions=["attn_scores_masked_softmax", "bmm_att_v"],
            with_cuda=True,
            verbose=False,
            extra_cuda_cflags=['-O3'],
            extra_cflags=['-O3'],
        )
    except Exception:
        _kb_ext = None
    return _kb_ext


class ModelNew(nn.Module):
    """
    Drop-in replacement for Model with accelerated attention using a custom CUDA extension.
    """

    def __init__(self, n_embd: int, n_head: int, attn_pdrop: float, resid_pdrop: float, max_seqlen: int):
        super().__init__()
        assert n_embd % n_head == 0
        self.c_attn = nn.Linear(n_embd, 3 * n_embd)
        self.c_proj = nn.Linear(n_embd, n_embd)
        self.attn_dropout = nn.Dropout(attn_pdrop)
        self.resid_dropout = nn.Dropout(resid_pdrop)
        self.register_buffer(
            "bias",
            torch.tril(torch.ones(max_seqlen, max_seqlen)).view(1, 1, max_seqlen, max_seqlen)
        )
        self.n_head = n_head
        self.n_embd = n_embd

        # Try building the CUDA extension once; fall back gracefully if it fails
        self._use_cuda_ext = False
        if torch.cuda.is_available():
            ext = _build_kb_ext()
            self._use_cuda_ext = ext is not None

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        B, T, C = x.size()
        nh = self.n_head
        hs = C // nh

        # Compute q, k, v projections
        q, k, v = self.c_attn(x).split(self.n_embd, dim=2)
        k = k.view(B, T, nh, hs).transpose(1, 2).contiguous()  # (B, nh, T, hs)
        q = q.view(B, T, nh, hs).transpose(1, 2).contiguous()  # (B, nh, T, hs)
        v = v.view(B, T, nh, hs).transpose(1, 2).contiguous()  # (B, nh, T, hs)

        use_cuda_ext = (
            self._use_cuda_ext
            and x.is_cuda
            and x.dtype == torch.float32
        )

        scale = 1.0 / math.sqrt(hs)

        if use_cuda_ext:
            # Compute attention probabilities with fused masked softmax
            att = _kb_ext.attn_scores_masked_softmax(q, k, float(scale))
        else:
            # Fallback: PyTorch reference path
            att = (q @ k.transpose(-2, -1)) * float(scale)
            att = att.masked_fill(self.bias[:, :, :T, :T] == 0, float('-inf'))
            att = F.softmax(att, dim=-1)

        att = self.attn_dropout(att)

        if use_cuda_ext:
            y = _kb_ext.bmm_att_v(att, v)  # (B, nh, T, hs)
        else:
            y = att @ v  # (B, nh, T, hs)

        y = y.transpose(1, 2).contiguous().view(B, T, C)

        y = self.resid_dropout(self.c_proj(y))
        return y

