import math
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Build CUDA extension once at import
kb_ext = load_inline(
    name="kb_ext",
    cpp_sources=[
        r"""
#include <torch/extension.h>

// Forward declaration only (implementation in CUDA sources)
torch::Tensor linear_matmul_bias_relu(torch::Tensor x,
                                      torch::Tensor w,
                                      torch::Tensor bias,
                                      bool apply_relu);
"""
    ],
    cuda_sources=[
        r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

namespace {

__global__ void add_bias_relu_kernel(const float* __restrict__ bias,
                                     float* __restrict__ out,
                                     int N, int C,
                                     int apply_relu_int) {
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    int n = blockIdx.y;
    if (n >= N || c >= C) return;
    int idx = n * C + c;
    float v = out[idx] + bias[c];
    if (apply_relu_int) {
        v = v > 0.0f ? v : 0.0f;
    }
    out[idx] = v;
}

} // anonymous namespace

torch::Tensor linear_matmul_bias_relu(torch::Tensor x,
                                      torch::Tensor w,
                                      torch::Tensor bias,
                                      bool apply_relu) {
    TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
    TORCH_CHECK(w.is_cuda(), "w must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
    TORCH_CHECK(x.scalar_type() == at::kFloat, "x must be float32");
    TORCH_CHECK(w.scalar_type() == at::kFloat, "w must be float32");
    TORCH_CHECK(bias.scalar_type() == at::kFloat, "bias must be float32");
    TORCH_CHECK(x.dim() == 2, "x must be 2D [N, in_features]");
    TORCH_CHECK(w.dim() == 2, "w must be 2D [out_features, in_features]");
    TORCH_CHECK(bias.dim() == 1, "bias must be 1D [out_features]");
    TORCH_CHECK(x.size(1) == w.size(1),
                "in_features mismatch: x.size(1)=", x.size(1), " vs w.size(1)=", w.size(1));
    TORCH_CHECK(w.size(0) == bias.size(0),
                "out_features mismatch: w.size(0)=", w.size(0), " vs bias.size(0)=", bias.size(0));

    auto x_c = x.contiguous();
    auto w_c = w.contiguous();
    auto b_c = bias.contiguous();

    // GEMM via cuBLAS (ATen)
    torch::Tensor out = at::matmul(x_c, w_c.t()); // [N, out_features]

    const int N = static_cast<int>(out.size(0));
    const int C = static_cast<int>(out.size(1));

    const int threads = 256;
    const int blocks_x = (C + threads - 1) / threads;
    const int blocks_y = N;
    dim3 grid(blocks_x, blocks_y);
    dim3 block(threads);

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    add_bias_relu_kernel<<<grid, block, 0, stream>>>(
        b_c.data_ptr<float>(),
        out.data_ptr<float>(),
        N, C,
        apply_relu ? 1 : 0
    );

    auto err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));

    return out;
}
""",
    ],
    functions=["linear_matmul_bias_relu"],
    with_cuda=True,
    verbose=False,
    extra_cuda_cflags=["-O3"],
    extra_cflags=["-O3"],
)


class ModelNew(nn.Module):
    def __init__(self, num_classes=1000):
        """
        :param num_classes: The number of output classes (default is 1000 for ImageNet)
        """
        super(ModelNew, self).__init__()

        # Mirror layers from reference Model for state/state_dict compatibility
        self.conv1 = nn.Conv2d(in_channels=3, out_channels=96, kernel_size=11, stride=4, padding=2)
        self.relu1 = nn.ReLU(inplace=True)
        self.maxpool1 = nn.MaxPool2d(kernel_size=3, stride=2)

        self.conv2 = nn.Conv2d(in_channels=96, out_channels=256, kernel_size=5, padding=2)
        self.relu2 = nn.ReLU(inplace=True)
        self.maxpool2 = nn.MaxPool2d(kernel_size=3, stride=2)

        self.conv3 = nn.Conv2d(in_channels=256, out_channels=384, kernel_size=3, padding=1)
        self.relu3 = nn.ReLU(inplace=True)

        self.conv4 = nn.Conv2d(in_channels=384, out_channels=384, kernel_size=3, padding=1)
        self.relu4 = nn.ReLU(inplace=True)

        self.conv5 = nn.Conv2d(in_channels=384, out_channels=256, kernel_size=3, padding=1)
        self.relu5 = nn.ReLU(inplace=True)
        self.maxpool3 = nn.MaxPool2d(kernel_size=3, stride=2)

        self.fc1 = nn.Linear(in_features=256 * 6 * 6, out_features=4096)
        self.relu6 = nn.ReLU(inplace=True)
        self.dropout1 = nn.Dropout(p=0.0)

        self.fc2 = nn.Linear(in_features=4096, out_features=4096)
        self.relu7 = nn.ReLU(inplace=True)
        self.dropout2 = nn.Dropout(p=0.0)

        self.fc3 = nn.Linear(in_features=4096, out_features=num_classes)

    @staticmethod
    def _use_accel(x: torch.Tensor, in_features: int, out_features: int) -> bool:
        if x.device.type != "cuda":
            return False
        if x.dtype != torch.float32:
            return False
        # Heuristics to avoid launch overhead on tiny problems
        N = x.shape[0]
        if N < 4:
            return False
        if min(in_features, out_features) < 64:
            return False
        return True

    def _linear_bias_relu(self, x: torch.Tensor, layer: nn.Linear, apply_relu: bool) -> torch.Tensor:
        # Fallback to PyTorch when not eligible
        if not self._use_accel(x, layer.in_features, layer.out_features):
            y = nn.functional.linear(x, layer.weight, layer.bias)
            if apply_relu:
                y = nn.functional.relu(y, inplace=False)
            return y
        # Ensure bias exists; if not, fallback for strict parity
        if layer.bias is None:
            y = nn.functional.linear(x, layer.weight, None)
            if apply_relu:
                y = nn.functional.relu(y, inplace=False)
            return y
        # Custom accelerated path: cuBLAS matmul + fused bias+ReLU kernel
        return kb_ext.linear_matmul_bias_relu(x, layer.weight, layer.bias, apply_relu)

    def forward(self, x):
        """
        :param x: The input tensor, shape (batch_size, 3, 224, 224)
        :return: The output tensor, shape (batch_size, num_classes)
        """
        # Convs remain in PyTorch/cuDNN
        x = self.conv1(x)
        x = self.relu1(x)
        x = self.maxpool1(x)

        x = self.conv2(x)
        x = self.relu2(x)
        x = self.maxpool2(x)

        x = self.conv3(x)
        x = self.relu3(x)

        x = self.conv4(x)
        x = self.relu4(x)

        x = self.conv5(x)
        x = self.relu5(x)
        x = self.maxpool3(x)

        x = torch.flatten(x, 1)

        # Accelerated fully-connected with fused bias+ReLU where applicable
        x = self._linear_bias_relu(x, self.fc1, apply_relu=True)
        x = self.dropout1(x)

        x = self._linear_bias_relu(x, self.fc2, apply_relu=True)
        x = self.dropout2(x)

        x = self._linear_bias_relu(x, self.fc3, apply_relu=False)

        return x

