import math
from typing import List, Tuple

import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline

# Build CUDA extension at import time (cached by name)
_cpp_decls = r"""
torch::Tensor depthwise_conv3x3_forward(torch::Tensor input,
                                        torch::Tensor weight,
                                        int stride_h, int stride_w,
                                        int pad_h, int pad_w);
"""

_cuda_impl = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#define TILE_H 16
#define TILE_W 16
#define SMEM_H (2 * TILE_H + 1)
#define SMEM_W (2 * TILE_W + 1)

__global__ void depthwise_conv3x3_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    float* __restrict__ output,
    int N, int C, int H, int W,
    int outH, int outW,
    int stride, int pad
) {
    extern __shared__ float smem[];
    // Grid mapping
    int bc = blockIdx.z;
    if (bc >= N * C) return;
    int n = bc / C;
    int c = bc % C;

    int tile_oh0 = blockIdx.y * TILE_H;
    int tile_ow0 = blockIdx.x * TILE_W;
    if (tile_oh0 >= outH || tile_ow0 >= outW) return;

    int tile_h_eff = outH - tile_oh0;
    if (tile_h_eff > TILE_H) tile_h_eff = TILE_H;
    int tile_w_eff = outW - tile_ow0;
    if (tile_w_eff > TILE_W) tile_w_eff = TILE_W;

    int in_tile_h = (tile_h_eff - 1) * stride + 3; // kernel_h = 3
    int in_tile_w = (tile_w_eff - 1) * stride + 3; // kernel_w = 3

    // Global base pointers (NCHW contiguous)
    const float* in_ptr  = input  + ((n * C + c) * H * W);
    float*       out_ptr = output + ((n * C + c) * outH * outW);

    // Load weights for this channel
    const float* w_ptr = weight + c * 9; // [C,1,3,3] contiguous per channel
    float w00 = w_ptr[0]; float w01 = w_ptr[1]; float w02 = w_ptr[2];
    float w10 = w_ptr[3]; float w11 = w_ptr[4]; float w12 = w_ptr[5];
    float w20 = w_ptr[6]; float w21 = w_ptr[7]; float w22 = w_ptr[8];

    // Compute starting input indices
    int in_h_start = tile_oh0 * stride - pad;
    int in_w_start = tile_ow0 * stride - pad;

    // Cooperative load into shared memory (bounded by SMEM_H x SMEM_W)
    for (int yy = threadIdx.y; yy < in_tile_h; yy += blockDim.y) {
        int ih = in_h_start + yy;
        bool h_in = (ih >= 0 && ih < H);
        for (int xx = threadIdx.x; xx < in_tile_w; xx += blockDim.x) {
            int iw = in_w_start + xx;
            float v = 0.0f;
            if (h_in && iw >= 0 && iw < W) {
                v = in_ptr[ih * W + iw];
            }
            smem[yy * SMEM_W + xx] = v;
        }
    }

    __syncthreads();

    // Compute outputs for this tile
    int ty = threadIdx.y;
    int tx = threadIdx.x;
    if (ty < tile_h_eff && tx < tile_w_eff) {
        int oh = tile_oh0 + ty;
        int ow = tile_ow0 + tx;

        int sh_base = (ty * stride) * SMEM_W + (tx * stride);

        float sum = 0.0f;
        // Unrolled 3x3
        sum += smem[sh_base + 0 * SMEM_W + 0] * w00;
        sum += smem[sh_base + 0 * SMEM_W + 1] * w01;
        sum += smem[sh_base + 0 * SMEM_W + 2] * w02;

        sum += smem[sh_base + 1 * SMEM_W + 0] * w10;
        sum += smem[sh_base + 1 * SMEM_W + 1] * w11;
        sum += smem[sh_base + 1 * SMEM_W + 2] * w12;

        sum += smem[sh_base + 2 * SMEM_W + 0] * w20;
        sum += smem[sh_base + 2 * SMEM_W + 1] * w21;
        sum += smem[sh_base + 2 * SMEM_W + 2] * w22;

        out_ptr[oh * outW + ow] = sum;
    }
}

torch::Tensor depthwise_conv3x3_forward(torch::Tensor input,
                                        torch::Tensor weight,
                                        int stride_h, int stride_w,
                                        int pad_h, int pad_w) {
    TORCH_CHECK(input.is_cuda(), "input must be CUDA");
    TORCH_CHECK(weight.is_cuda(), "weight must be CUDA");
    TORCH_CHECK(input.scalar_type() == at::kFloat, "only float32 supported");
    TORCH_CHECK(weight.scalar_type() == at::kFloat, "only float32 supported");
    TORCH_CHECK(input.dim() == 4, "input must be NCHW");
    TORCH_CHECK(weight.dim() == 4, "weight must be [C,1,3,3]");
    TORCH_CHECK(weight.size(1) == 1 && weight.size(2) == 3 && weight.size(3) == 3, "weight must be [C,1,3,3]");
    TORCH_CHECK(stride_h == stride_w, "only equal strides supported in this kernel");
    TORCH_CHECK(pad_h == pad_w, "only equal padding supported in this kernel");

    auto in = input.contiguous();
    auto w  = weight.contiguous();

    int64_t N = in.size(0);
    int64_t C = in.size(1);
    int64_t H = in.size(2);
    int64_t W = in.size(3);
    TORCH_CHECK(w.size(0) == C, "weight C mismatch");

    int stride = stride_h;
    int pad = pad_h;

    // Output dims for conv: out = floor((H + 2*pad - 3)/stride) + 1
    int outH = (int)((H + 2 * pad - 3) / stride + 1);
    int outW = (int)((W + 2 * pad - 3) / stride + 1);

    auto out = torch::empty({N, C, outH, outW}, in.options());

    dim3 block(TILE_W, TILE_H);
    dim3 grid((outW + TILE_W - 1) / TILE_W,
              (outH + TILE_H - 1) / TILE_H,
              N * C);

    size_t shmem_bytes = (size_t)SMEM_H * (size_t)SMEM_W * sizeof(float);

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    depthwise_conv3x3_kernel<<<grid, block, shmem_bytes, stream>>>(
        in.data_ptr<float>(),
        w.data_ptr<float>(),
        out.data_ptr<float>(),
        (int)N, (int)C, (int)H, (int)W,
        outH, outW,
        stride, pad
    );

    auto err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, "depthwise_conv3x3_kernel launch failed: ", cudaGetErrorString(err));
    return out;
}
"""

try:
    kb_ext = load_inline(
        name="kb_ext",
        cpp_sources=[_cpp_decls],
        cuda_sources=[_cuda_impl],
        functions=["depthwise_conv3x3_forward"],
        with_cuda=True,
        extra_cuda_cflags=["-O3"],
        extra_cflags=["-O3"],
        verbose=False,
    )
except Exception as _e:
    kb_ext = None


class DepthwiseConv3x3CUDA(nn.Conv2d):
    def __init__(self, channels: int, stride: int):
        # groups equals in_channels equals out_channels for depthwise
        super().__init__(in_channels=channels,
                         out_channels=channels,
                         kernel_size=3,
                         stride=stride,
                         padding=1,
                         dilation=1,
                         groups=channels,
                         bias=False)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        use_cuda_kernel = (
            kb_ext is not None and
            x.is_cuda and
            x.dtype == torch.float32 and
            self.weight is not None and
            self.weight.is_cuda and
            self.weight.dtype == torch.float32 and
            self.kernel_size == (3, 3) and
            self.padding == (1, 1) and
            self.groups == self.in_channels == self.out_channels and
            self.bias is None and
            self.dilation == (1, 1)
        )
        if use_cuda_kernel:
            # weight shape: [C,1,3,3] for depthwise
            return kb_ext.depthwise_conv3x3_forward(
                x, self.weight, self.stride[0], self.stride[1], self.padding[0], self.padding[1]
            )
        else:
            return F.conv2d(x, self.weight, self.bias, self.stride,
