import os
import warnings
import random
import string
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

def _unique_name(prefix="ext"):
    suffix = ''.join(random.choice(string.ascii_lowercase + string.digits) for _ in range(8))
    return f"{prefix}_{os.getpid()}_{suffix}"

def _build_linear_ext():
    cpp_src = r"""
    #include <torch/extension.h>

    torch::Tensor addmm_ext(torch::Tensor X, torch::Tensor W_t, torch::Tensor bias);
    torch::Tensor matmul_ext(torch::Tensor X, torch::Tensor W_t);
    """

    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    torch::Tensor addmm_ext(torch::Tensor X, torch::Tensor W_t, torch::Tensor bias) {
        TORCH_CHECK(X.is_cuda() && W_t.is_cuda() && bias.is_cuda(), "Inputs must be CUDA tensors");
        TORCH_CHECK(X.scalar_type() == at::kFloat && W_t.scalar_type() == at::kFloat && bias.scalar_type() == at::kFloat, "dtype must be float32");
        TORCH_CHECK(X.dim()==2 && W_t.dim()==2 && bias.dim()==1, "Shapes must be [B,K], [K,O], [O]");
        TORCH_CHECK(X.size(1)==W_t.size(0) && W_t.size(1)==bias.size(0), "Shape mismatch");
        if (!X.is_contiguous()) X = X.contiguous();
        if (!W_t.is_contiguous()) W_t = W_t.contiguous();
        if (!bias.is_contiguous()) bias = bias.contiguous();
        auto Y = at::matmul(X, W_t);
        return Y.add_(bias);
    }

    torch::Tensor matmul_ext(torch::Tensor X, torch::Tensor W_t) {
        TORCH_CHECK(X.is_cuda() && W_t.is_cuda(), "Inputs must be CUDA tensors");
        TORCH_CHECK(X.scalar_type() == at::kFloat && W_t.scalar_type() == at::kFloat, "dtype must be float32");
        TORCH_CHECK(X.dim()==2 && W_t.dim()==2, "Shapes must be [B,K], [K,O]");
        TORCH_CHECK(X.size(1)==W_t.size(0), "Shape mismatch");
        if (!X.is_contiguous()) X = X.contiguous();
        if (!W_t.is_contiguous()) W_t = W_t.contiguous();
        return at::matmul(X, W_t);
    }
    """

    try:
        ext = load_inline(
            name=_unique_name("linear_ops"),
            cpp_sources=[cpp_src],
            cuda_sources=[cuda_src],
            functions=["addmm_ext", "matmul_ext"],
            extra_cflags=["-O3"],
            extra_cuda_cflags=["-O3"],
            verbose=False,
        )
        return ext
    except Exception as e:
        warnings.warn(f"CUDA extension build failed. Falling back to PyTorch ops. Error: {e}")
        return None

# Build once at module import and cache
_LINEAR_EXT = _build_linear_ext() if torch.cuda.is_available() else None


class ModelNew(nn.Module):
    def __init__(self, input_size, hidden_size, num_layers, output_size, dropout=0.0):
        """
        Initialize the LSTM model.

        :param input_size: The number of expected features in the input `x`
        :param hidden_size: The number of features in the hidden state `h`
        :param num_layers: Number of recurrent layers
        :param output_size: The number of output features
        :param dropout: If non-zero, introduces a Dropout layer on the outputs of each LSTM layer except the last layer, with dropout probability equal to `dropout`
        """
        super(ModelNew, self).__init__()
        self.lstm = nn.LSTM(input_size, hidden_size, num_layers, batch_first=True, dropout=dropout, bidirectional=True)
        self.fc = nn.Linear(hidden_size * 2, output_size)

        # Extension usage
        self._ext = _LINEAR_EXT
        self.use_ext = self._ext is not None

        # Cached transposed weight and metadata
        self._w_t = None
        self._w_version = -1
        self._w_device = None
        self._w_dtype = None

    def _maybe_update_wt(self):
        W = self.fc.weight
        if (
            self._w_t is None
            or self._w_version != W._version
            or self._w_device != W.device
            or self._w_dtype != W.dtype
        ):
            # Cache transposed weights on the correct device/dtype
            self._w_t = W.detach().t().contiguous()
            self._w_version = W._version
            self._w_device = W.device
            self._w_dtype = W.dtype

    def forward(self, x, h0, c0):
        """
        Forward pass through the LSTM model.

        :param x: The input tensor, shape (batch_size, sequence_length, input_size)
        :return: The output tensor, shape (batch_size, output_size)
        """
        out, hn = self.lstm(x, (h0, c0))  # out: (B, T, 2H)
        last = out[:, -1, :]  # (B, 2H)

        can_use_ext = (
            self.use_ext
            and last.is_cuda
            and last.dtype == torch.float32
            and self.fc.weight.is_cuda
            and self.fc.weight.dtype == torch.float32
            and (self.fc.bias is None or (self.fc.bias.is_cuda and self.fc.bias.dtype == torch.float32))
        )

        if can_use_ext:
            # Update cached transposed weights if needed
            self._maybe_update_wt()
            if self.fc.bias is not None:
                return self._ext.addmm_ext(last, self._w_t, self.fc.bias)
            else:
                return self._ext.matmul_ext(last, self._w_t)
        else:
            # Fallback: pure PyTorch path (autograd friendly)
            return self.fc(last)


